mapper.select:
SELECT * FROM (
	SELECT A.MESSAGE_ID, A.SEND_MEM_ID, B.MEM_NAME, A.SEND_DATE, A.RECEIVE_DATE
			, A.CONTENT, B.MEM_PICTURE
	FROM WH_USER_MESSAGE A INNER JOIN WH_MEMBER B ON A.SEND_MEM_ID = B.MEM_ID
	WHERE A.RECEIVE_MEM_ID = #{RECEIVE_MEM_ID}
	AND A.SEND_MEM_ID = #{SEND_MEM_ID}
	AND A.DELETE_DATE IS NULL
	
	UNION ALL
	
	SELECT A.MESSAGE_ID, A.SEND_MEM_ID, B.MEM_NAME, A.SEND_DATE, A.RECEIVE_DATE
			, A.CONTENT, B.MEM_PICTURE
	FROM WH_USER_MESSAGE A INNER JOIN WH_MEMBER B ON A.SEND_MEM_ID = B.MEM_ID
	WHERE A.RECEIVE_MEM_ID = #{SEND_MEM_ID}
	AND A.SEND_MEM_ID = #{RECEIVE_MEM_ID}
	AND A.DELETE_DATE IS NULL
) P
ORDER BY P.SEND_DATE

